import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface TrafficSource {
  source: string;
  value: number;
}

interface Overview {
  visitors: number;
  pageViews: number;
  bounceRate: number;
}

interface AnalyticsData {
  overview: Overview;
  trafficSources: TrafficSource[];
}

export default function Widget() {
  const analyticsData = response.data as AnalyticsData;
  const { overview, trafficSources } = analyticsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#0288D1' }}>
              Site Stats
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Visitors: {overview.visitors.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Page Views: {overview.pageViews.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Bounce Rate: {overview.bounceRate}%
            </Typography>
          </Box>

          <PieChart
            height={200}
            series={[
              {
                data: trafficSources.map((source) => ({ id: source.source, value: source.value })),
                colorScheme: ['#0288D1', '#FFC107', '#FF7043', '#AB47BC', '#29B6F6'],
              },
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiPieSlice-label': {
                fontSize: 10,
                fill: '#6B7280',
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
